import{_ as e,a as t,b as i}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as d,o as l,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Tambah Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/cloudflare-r2.md","filePath":"ms-MY/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),o={name:"ms-MY/upload/cloudflare-r2.md"};function u(c,a,m,s,h,p){return l(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="tambah-cloudflare-r2-channel" tabindex="-1">Tambah Cloudflare R2 Channel <a class="header-anchor" href="#tambah-cloudflare-r2-channel" aria-label="Permalink to &quot;Tambah Cloudflare R2 Channel&quot;">​</a></h1><h2 id="paling-sesuai-untuk" tabindex="-1">Paling Sesuai Untuk <a class="header-anchor" href="#paling-sesuai-untuk" aria-label="Permalink to &quot;Paling Sesuai Untuk&quot;">​</a></h2><p>Gunakan Cloudflare R2 apabila:</p><ul><li>ImgBed site anda sudah deploy di Cloudflare dan anda mahu menyimpan files dalam R2 bucket di bawah Cloudflare account yang sama.</li><li>Anda tidak mahu mengkonfigurasi S3 endpoint, access key dan secret key secara berasingan.</li><li>Anda mahu read dan write berjalan melalui Worker atau Pages R2 binding dengan setup minimum.</li></ul><p>Ringkasnya:</p><p>R2 channel tidak dicipta secara manual dalam ImgBed admin panel. Anda perlu bind R2 bucket kepada Cloudflare project terlebih dahulu, dan binding variable name mesti <code>img_r2</code>.</p><h2 id="perkara-yang-perlu-disediakan" tabindex="-1">Perkara Yang Perlu Disediakan <a class="header-anchor" href="#perkara-yang-perlu-disediakan" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan&quot;">​</a></h2><ul><li>Cloudflare account.</li><li>R2 bucket yang sudah wujud.</li><li>Permission untuk mengurus Cloudflare project tempat ImgBed dideploy.</li></ul><h2 id="configure-dalam-cloudflare" tabindex="-1">Configure Dalam Cloudflare <a class="header-anchor" href="#configure-dalam-cloudflare" aria-label="Permalink to &quot;Configure Dalam Cloudflare&quot;">​</a></h2><h3 id="_1-cipta-r2-bucket" tabindex="-1">1. Cipta R2 Bucket <a class="header-anchor" href="#_1-cipta-r2-bucket" aria-label="Permalink to &quot;1. Cipta R2 Bucket&quot;">​</a></h3><ol><li>Log in ke Cloudflare Dashboard.</li><li>Buka <code>R2 Object Storage</code>.</li><li>Klik Create bucket.</li><li>Pilih bucket name, contohnya <code>imgbed</code>.</li></ol><p>Bucket ini akan menyimpan uploaded files.</p><p><img src="'+e+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-bucket-kepada-imgbed-project" tabindex="-1">2. Bind Bucket Kepada ImgBed Project <a class="header-anchor" href="#_2-bind-bucket-kepada-imgbed-project" aria-label="Permalink to &quot;2. Bind Bucket Kepada ImgBed Project&quot;">​</a></h3><p>Pilih lokasi binding berdasarkan deployment type:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Semasa menambah binding, field penting ialah:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Pilih bucket yang anda cipta.</td></tr></tbody></table><p>Variable name mesti tepat <code>img_r2</code>. Upload, read dan delete R2 files semuanya bergantung pada binding name ini.</p><h3 id="_3-redeploy-project" tabindex="-1">3. Redeploy Project <a class="header-anchor" href="#_3-redeploy-project" aria-label="Permalink to &quot;3. Redeploy Project&quot;">​</a></h3><p>Selepas menyimpan binding, redeploy ImgBed supaya Worker atau Pages runtime boleh mengakses <code>img_r2</code>.</p><h2 id="apa-yang-akan-dilihat-dalam-imgbed" tabindex="-1">Apa Yang Akan Dilihat Dalam ImgBed <a class="header-anchor" href="#apa-yang-akan-dilihat-dalam-imgbed" aria-label="Permalink to &quot;Apa Yang Akan Dilihat Dalam ImgBed&quot;">​</a></h2><p>Selepas R2 binding tersedia, buka:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li><code>Cloudflare R2</code> channel.</li></ol><p>System akan mencipta satu fixed channel secara automatik:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>Ini ialah fixed binding channel. Anda tidak perlu klik Add Channel untuk menciptanya, dan ia tidak boleh dipadam seperti regular channel.</p><h2 id="field-yang-boleh-diedit-dalam-admin-panel" tabindex="-1">Field Yang Boleh Diedit Dalam Admin Panel <a class="header-anchor" href="#field-yang-boleh-diedit-dalam-admin-panel" aria-label="Permalink to &quot;Field Yang Boleh Diedit Dalam Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>Mengawal sama ada R2 terlibat dalam upload selection.</td><td>Yes</td></tr><tr><td>Account ID</td><td>Digunakan hanya apabila quota limits diaktifkan dan official R2 usage perlu di-query.</td><td>Recommended apabila quota limits diaktifkan</td></tr><tr><td>Bucket name</td><td>Digunakan hanya apabila quota limits diaktifkan dan official R2 usage perlu di-query.</td><td>Recommended apabila quota limits diaktifkan</td></tr><tr><td>Quota limit</td><td>Mengawal sama ada R2 channel ini terlibat dalam upload selection berdasarkan capacity.</td><td>No</td></tr><tr><td>Threshold</td><td>Berhenti menulis ke channel ini selepas usage mencapai percentage yang ditetapkan.</td><td>Required apabila quota limits diaktifkan</td></tr></tbody></table><p>Anda boleh copy Account ID daripada account information panel dalam Cloudflare dashboard. Isi hanya jika anda mahu ImgBed query dan enforce R2 quota usage.</p><p><img src="'+t+'" alt="Get the Account ID" loading="lazy"></p><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><ol><li>Cipta R2 bucket dalam Cloudflare.</li><li>Buka Cloudflare settings untuk ImgBed project.</li><li>Tambah R2 bucket binding.</li><li>Tetapkan <code>Variable name</code> kepada <code>img_r2</code>.</li><li>Pilih R2 bucket yang anda cipta.</li><li>Save binding dan redeploy ImgBed.</li><li>Kembali ke ImgBed -&gt; System Settings -&gt; Upload Settings.</li><li>Pastikan <code>Cloudflare R2</code> channel muncul dan enabled.</li></ol><p>Jika mahu R2 terlibat dalam upload selection berdasarkan capacity, enable quota limit, kemudian isi Account ID, bucket name, quota limit dan threshold sebelum save.</p><p><img src="'+i+'" alt="Configure quota limits" loading="lazy"></p><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><ul><li>Fixed <code>Cloudflare R2</code> channel muncul dalam Upload Settings.</li><li>Channel card menunjukkan ia enabled.</li><li>Small test file berjaya di-upload dan returned link dibuka secara normal.</li><li>Jika membuka file memaparkan <code>R2 database binding is not configured</code>, runtime tidak menerima <code>img_r2</code> binding. Semak binding name dalam Cloudflare dan redeploy project.</li></ul>',37)])])}const f=d(o,[["render",u]]);export{k as __pageData,f as default};
